-- KB: enrich flow-templates how-to and add template catalog article (EN + VI)

-- ── Update existing EN how-to ─────────────────────────────────────────────────

UPDATE knowledge_base SET
  content_markdown = E'# How to Use Flow Templates\n\nBizFlow ships with a ready-made template library covering the most common workplace processes. Templates are a fast way to get a working flow without building from scratch — clone one, adjust the form fields and assignee rules to match your team, and publish.\n\n## Accessing the template gallery\n\nTemplates are available to **admins only**.\n\n1. Go to **Flows** in the left sidebar\n2. Click the **Templates** button in the toolbar (top-right of the flow list)\n3. The gallery opens as an overlay showing all published templates grouped by category\n4. Use the category tabs — **All · HR · Finance · IT · Operations · Other** — to filter\n\n## Cloning a template\n\n1. Browse or filter to find the template you want\n2. Click **Use template** on the card\n3. BizFlow creates a new **draft** flow in your workspace with the full canvas pre-built\n4. You are taken straight to the flow builder to review and customise it\n\n## What is copied\n\n| Element | Copied? | Notes |\n|---------|---------|-------|\n| Steps and connections | ✅ Yes | Full canvas graph |\n| Form fields and field types | ✅ Yes | Labels, required flags, dropdown options |\n| Branch conditions | ✅ Yes | Yes/No routing logic |\n| Generic assignee rules | ✅ Yes | Requester, Manager, Skip-level, Dept head |\n| Fixed-email assignee rules | ❌ Removed | Must be set in your workspace |\n| Tenant-specific dept/role rules | ❌ Removed | Must be set in your workspace |\n| SLA deadlines | ✅ Yes | Hours are copied; adjust as needed |\n\n## Customising after cloning\n\nMost templates work straight away with generic assignee rules, but you may want to:\n\n- **Rename steps** to match your company terminology\n- **Add or remove form fields** — click a step node, then open the Fields panel\n- **Set specific assignees** — if a step should always go to a named person or department, update the Assignee Rule\n- **Adjust SLA deadlines** — each step can have its own due-within setting\n- **Restrict who can trigger the flow** — use the Trigger Restrictions setting in the Publish panel to limit it to specific departments\n\n## Publishing\n\nWhen you are happy with the customised flow, open the **Publish** panel on the right sidebar and click **Publish**. The flow is immediately available for your team to trigger.\n\n## Plan limits\n\nCloning a template creates a new flow in your workspace and counts towards your plan''s flow limit. Free plan workspaces are limited to 2 flows total.\n\n## Suggesting new templates\n\nDo not see a template for your use case? Email us at **contact@bizflow.id.vn** and we will consider adding it to the library.\n\n## See also\n\n- [Available Flow Templates](/help/available-flow-templates) — browse the full catalog\n- [How to Create a Workflow](/help/how-to-create-workflow) — build from scratch\n- [How to Configure Assignee Rules](/help/how-to-configure-assignee-rules)',
  updated_at = NOW()
WHERE slug = 'how-to-use-flow-templates';

-- ── Update existing VI how-to ─────────────────────────────────────────────────

UPDATE knowledge_base SET
  content_markdown = E'# Cách sử dụng mẫu quy trình\n\nBizFlow cung cấp thư viện mẫu quy trình sẵn có cho các quy trình làm việc phổ biến nhất. Mẫu giúp bạn có một quy trình hoạt động ngay mà không cần xây dựng từ đầu — sao chép mẫu, điều chỉnh trường biểu mẫu và quy tắc phân công cho phù hợp với nhóm của bạn, rồi công bố.\n\n## Truy cập thư viện mẫu\n\nMẫu quy trình chỉ dành cho **Quản trị viên**.\n\n1. Vào **Quy trình** trong thanh bên trái\n2. Nhấn nút **Mẫu** trên thanh công cụ (góc trên bên phải)\n3. Thư viện mở ra dưới dạng overlay với tất cả mẫu đã công bố, phân theo danh mục\n4. Dùng các tab danh mục — **Tất cả · HR · Tài chính · IT · Vận hành · Khác** — để lọc\n\n## Sao chép mẫu\n\n1. Duyệt hoặc lọc để tìm mẫu phù hợp\n2. Nhấn **Dùng mẫu này** trên thẻ mẫu\n3. BizFlow tạo một quy trình **nháp** mới trong không gian làm việc của bạn với canvas đã được xây dựng sẵn\n4. Bạn được chuyển thẳng vào trình chỉnh sửa quy trình để xem xét và tùy chỉnh\n\n## Nội dung được sao chép\n\n| Thành phần | Sao chép? | Ghi chú |\n|------------|-----------|--------|\n| Các bước và kết nối | ✅ Có | Toàn bộ canvas |\n| Trường biểu mẫu | ✅ Có | Nhãn, bắt buộc, tùy chọn dropdown |\n| Điều kiện rẽ nhánh | ✅ Có | Logic định tuyến Có/Không |\n| Quy tắc phân công chung | ✅ Có | Người yêu cầu, Quản lý, Skip-level, Trưởng phòng |\n| Quy tắc phân công cố định (email) | ❌ Bị xóa | Cần cài lại trong workspace |\n| Quy tắc theo phòng ban/vai trò cụ thể | ❌ Bị xóa | Cần cài lại trong workspace |\n| Thời hạn SLA | ✅ Có | Số giờ được giữ nguyên; điều chỉnh nếu cần |\n\n## Tùy chỉnh sau khi sao chép\n\nHầu hết mẫu hoạt động ngay với quy tắc phân công chung, nhưng bạn có thể muốn:\n\n- **Đổi tên bước** cho phù hợp với thuật ngữ của công ty\n- **Thêm hoặc xóa trường biểu mẫu** — nhấn vào nút bước, rồi mở bảng Trường\n- **Đặt người phụ trách cụ thể** — cập nhật Quy tắc phân công nếu bước nên luôn đến một người hoặc phòng ban cụ thể\n- **Điều chỉnh thời hạn SLA** — mỗi bước có thể có thời hạn riêng\n- **Giới hạn ai có thể kích hoạt** — dùng cài đặt Giới hạn kích hoạt trong bảng Công bố\n\n## Công bố\n\nKhi bạn hài lòng với quy trình đã tùy chỉnh, mở bảng **Công bố** ở thanh bên phải và nhấn **Công bố**. Quy trình sẽ ngay lập tức có sẵn cho nhóm của bạn.\n\n## Giới hạn gói\n\nSao chép mẫu tạo ra một quy trình mới và được tính vào giới hạn quy trình của gói. Gói Free giới hạn tổng cộng 2 quy trình.\n\n## Gợi ý mẫu mới\n\nKhông tìm thấy mẫu phù hợp? Hãy gửi email đến **contact@bizflow.id.vn** và chúng tôi sẽ xem xét bổ sung.\n\n## Xem thêm\n\n- [Danh sách mẫu quy trình](/help/available-flow-templates-vi) — duyệt toàn bộ danh mục\n- [Cách tạo quy trình làm việc](/help/how-to-create-workflow-vi) — xây dựng từ đầu\n- [Cách cấu hình quy tắc phân công](/help/how-to-configure-assignee-rules-vi)',
  updated_at = NOW()
WHERE slug = 'how-to-use-flow-templates-vi';

